import{_ as t,o as a,c as e,ag as r}from"./chunks/framework.eQLvDOR_.js";const m=JSON.parse('{"title":"caching-vs-rag-economics","description":"","frontmatter":{"title":"caching-vs-rag-economics","connection_id":"caching-vs-rag-economics","related_concepts":["[[context-optimization]]","[[notebooklm-rag-orchestration]]"],"created_at":"2026-04-21","last_compiled":"2026-04-21"},"headers":[],"relativePath":"wiki/connections/caching-vs-rag-economics.md","filePath":"wiki/connections/caching-vs-rag-economics.md","lastUpdated":null}'),n={name:"wiki/connections/caching-vs-rag-economics.md"};function i(l,o,s,c,d,h){return a(),e("div",null,[...o[0]||(o[0]=[r('<h1 id="成本博弈-缓存命中-vs-rag-引擎" tabindex="-1">成本博弈：缓存命中 vs. RAG 引擎 <a class="header-anchor" href="#成本博弈-缓存命中-vs-rag-引擎" aria-label="Permalink to &quot;成本博弈：缓存命中 vs. RAG 引擎&quot;">​</a></h1><h2 id="核心矛盾" tabindex="-1">核心矛盾 <a class="header-anchor" href="#核心矛盾" aria-label="Permalink to &quot;核心矛盾&quot;">​</a></h2><p>在长文本研究任务中，用户面临两种成本节省方案的选择。</p><h3 id="_1-缓存方案-prompt-caching" tabindex="-1">1. 缓存方案 (Prompt Caching) <a class="header-anchor" href="#_1-缓存方案-prompt-caching" aria-label="Permalink to &quot;1. 缓存方案 (Prompt Caching)&quot;">​</a></h3><ul><li><strong>原理</strong>：将全文塞入 Context，利用 <code>cache_creation</code> 建立缓存。</li><li><strong>优势</strong>：读取延迟最低，模型能保持对全文的 100% “全神贯注”。</li><li><strong>劣势</strong>： <ul><li><strong>TTL 风险</strong>：研究任务中思路常中断。1 小时后失效导致单次检索可能需要花费 $10+ 重新建立缓存。</li><li><strong>累加效应</strong>：多轮对话后，即使缓存命中了，单次对话的残余 Token 成本仍会随轮次抬升。</li></ul></li></ul><h3 id="_2-rag-方案-notebooklm-深度辅助" tabindex="-1">2. RAG 方案 (NotebookLM 深度辅助) <a class="header-anchor" href="#_2-rag-方案-notebooklm-深度辅助" aria-label="Permalink to &quot;2. RAG 方案 (NotebookLM 深度辅助)&quot;">​</a></h3><ul><li><strong>原理</strong>：将全文留存在外部 RAG 引擎。</li><li><strong>优势</strong>： <ul><li><strong>经济效率</strong>：在大规模语料（如 50 篇论文）场景下，成本比缓存方案低 <strong>17~86 倍</strong>。</li><li><strong>零时效压力</strong>：检索过程在 Google 侧免费且永不过期。</li></ul></li><li><strong>劣势</strong>： <ul><li><strong>速度瓶颈</strong>：单次检索通常耗时 40s+（比直接读取慢 2-3 倍）。</li><li><strong>上下文碎片</strong>：模型只能看到片段，可能遗漏跨段落的极隐性关联。</li></ul></li></ul><h2 id="决策矩阵" tabindex="-1">决策矩阵 <a class="header-anchor" href="#决策矩阵" aria-label="Permalink to &quot;决策矩阵&quot;">​</a></h2><table tabindex="0"><thead><tr><th>模型 / 规模</th><th>少量语料 (&lt;5K tokens)</th><th>海量语料 (&gt;50K tokens)</th><th>研究型长对话 (3天+)</th></tr></thead><tbody><tr><td><strong>Prompt Cache</strong></td><td>✅ 极力推荐 (极速且便宜)</td><td>⚠️ 慎重 (一旦缓存断裂成本报表)</td><td>❌ 不推荐</td></tr><tr><td><strong>NotebookLM TAP</strong></td><td>❌ 流程太重</td><td>✅ 极力推荐 (省钱利器)</td><td>✅ 建立长期专家库</td></tr></tbody></table><h2 id="结论" tabindex="-1">结论 <a class="header-anchor" href="#结论" aria-label="Permalink to &quot;结论&quot;">​</a></h2><p><strong>真正省钱的办法不是开 cache，是让重数据一开始就不进 Claude。</strong> 对于 2026 年的高阶 AI 用户（如使用 Max 套餐的用户），将 NotebookLM 作为持久化“老师”层，Claude 作为即时“处理”层，是目前最科学的知识库工程组合。</p><hr><h2 id="参考链接" tabindex="-1">参考链接 <a class="header-anchor" href="#参考链接" aria-label="Permalink to &quot;参考链接&quot;">​</a></h2><ul><li><a href="/s/webclips/library/AI_Prompt_Engineering/AI_Prompt_Engineering - 搞懂缓存机制，从Gemma4到Claude Code省80%Token.html">[AI_Prompt_Engineering] 搞懂缓存机制，从Gemma4到Claude Code省80%Token</a></li><li><a href="/s/webclips/library/NotebookLM_Workflows/NotebookLM_Workflows - 用好 NotebookLM 立省 80 Token.html">[NotebookLM_Workflows] 用好 NotebookLM 立省 80 Token</a></li></ul>',14)])])}const _=t(n,[["render",i]]);export{m as __pageData,_ as default};
